1	type Item = { type: string; cursed?: boolean; enchantment?: number };
2	type Damage = { itemType: string; amount: number };
3	type Incident = { cause?: string; damages: Damage[] };
4	type QuoteStep = { op?: "quote"; items: Item[] };
5	type ClaimStep = { op: "claim"; policy: number; incident: Incident };
6	type Step = QuoteStep | ClaimStep;
7	type Scenario = { customer?: { yearsWithMHPCO?: number }; steps: Step[] };
8	
9	const PROCESSING_FEE = 5;
10	const COMPONENT_BASE_PER_ITEM = 25;
11	const COMPONENT_BLOCK_OF_THREE_BASE = 60;
12	
13	const CURSED_SURCHARGE_RATE = 0.5;
14	const HIGH_ENCHANTMENT_SURCHARGE_RATE = 0.3;
15	const FIRST_INSURANCE_MARKUP_RATE = 0.1;
16	const LOYALTY_DISCOUNT_RATE = 0.2;
17	const FOLLOW_UP_DISCOUNT_RATE = 0.15;
18	const LOYALTY_YEARS_THRESHOLD = 2;
19	const HIGH_ENCHANTMENT_THRESHOLD = 5;
20	
21	const CLAIM_DEDUCTIBLE = 100;
22	const CAP_MULTIPLIER = 2;
23	const HIGH_ENCHANTMENT_CLAIM_THRESHOLD = 8;
24	const HIGH_ENCHANTMENT_REIMBURSEMENT_RATE = 0.5;
25	
26	const BASE_PREMIUM_BY_TYPE: Record<string, number> = {
27	  sword: 100,
28	  amulet: 60,
29	  staff: 80,
30	  potion: 40,
31	};
32	
33	const INSURANCE_VALUE_BY_TYPE: Record<string, number> = {
34	  sword: 1000,
35	  amulet: 600,
36	  rune: 250,
37	};
38	
39	type PolicyState = { items: Item[]; remainingCap: number };
40	
41	export function runScenario(input: unknown): unknown {
42	  const { customer, steps } = input as Scenario;
43	  const years = customer?.yearsWithMHPCO ?? 0;
44	  const policies: Record<number, PolicyState> = {};
45	  const results = steps.map((step, index) => {
46	    if (step.op === "claim") return computeClaim(step, policies);
47	    const isFollowUp = index >= 1;
48	    policies[index] = { items: step.items, remainingCap: CAP_MULTIPLIER * insuranceSumFor(step.items) };
49	    return { premium: computePremium(step.items, years, isFollowUp) };
50	  });
51	  return { results };
52	}
53	
54	function insuranceSumFor(items: Item[]): number {
55	  return items.reduce((sum, item) => sum + INSURANCE_VALUE_BY_TYPE[item.type], 0);
56	}
57	
58	function computeClaim(step: ClaimStep, policies: Record<number, PolicyState>): { payout: number; remainingCap: number } {
59	  const policy = policies[step.policy];
60	  const payout = step.incident.damages.reduce((sum, damage) => sum + reimbursementFor(damage, policy.items), 0);
61	  policy.remainingCap -= payout;
62	  return { payout, remainingCap: policy.remainingCap };
63	}
64	
65	function reimbursementFor(damage: Damage, items: Item[]): number {
66	  const item = items.find((i) => i.type === damage.itemType);
67	  const reimbursable = item !== undefined && (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_CLAIM_THRESHOLD
68	    ? damage.amount * HIGH_ENCHANTMENT_REIMBURSEMENT_RATE
69	    : damage.amount;
70	  return Math.max(0, reimbursable - CLAIM_DEDUCTIBLE);
71	}
72	
73	function computePremium(items: Item[], years: number, isFollowUp: boolean): number {
74	  if (items.length === 0) return PROCESSING_FEE;
75	  if (items.every(isComponent)) return componentsPremium(items);
76	  return mainItemsPremium(items, years, isFollowUp);
77	}
78	
79	function mainItemsPremium(items: Item[], years: number, isFollowUp: boolean): number {
80	  const policyBase = items.reduce((sum, item) => sum + BASE_PREMIUM_BY_TYPE[item.type], 0);
81	  const itemSubtotalSum = items.reduce((sum, item) => sum + itemSubtotal(item), 0);
82	  const policyMod = (cond: boolean, rate: number) => (cond ? policyBase * rate : 0);
83	  const loyaltyDiscount = policyMod(years >= LOYALTY_YEARS_THRESHOLD, LOYALTY_DISCOUNT_RATE);
84	  const followUpDiscount = policyMod(isFollowUp, FOLLOW_UP_DISCOUNT_RATE);
85	  return Math.ceil(itemSubtotalSum - loyaltyDiscount - followUpDiscount) + PROCESSING_FEE;
86	}
87	
88	function itemSubtotal(item: Item): number {
89	  const base = BASE_PREMIUM_BY_TYPE[item.type];
90	  const surchargeIf = (cond: boolean, rate: number) => (cond ? base * rate : 0);
91	  const cursedSurcharge = surchargeIf(item.cursed === true, CURSED_SURCHARGE_RATE);
92	  const highEnchSurcharge = surchargeIf(isHighlyEnchanted(item), HIGH_ENCHANTMENT_SURCHARGE_RATE);
93	  const firstInsuranceMarkup = base * FIRST_INSURANCE_MARKUP_RATE;
94	  return base + cursedSurcharge + highEnchSurcharge + firstInsuranceMarkup;
95	}
96	
97	function isHighlyEnchanted(item: Item): boolean {
98	  return (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD;
99	}
100	
101	function componentsPremium(items: Item[]): number {
102	  const runes = items.filter((i) => i.type === "rune").length;
103	  const moonstones = items.filter((i) => i.type === "moonstone").length;
104	  return premiumFromBase(componentTypeBase(runes) + componentTypeBase(moonstones));
105	}
106	
107	function componentTypeBase(count: number): number {
108	  return count === 3 ? COMPONENT_BLOCK_OF_THREE_BASE : count * COMPONENT_BASE_PER_ITEM;
109	}
110	
111	function isComponent(item: Item): boolean {
112	  return item.type === "rune" || item.type === "moonstone";
113	}
114	
115	function premiumFromBase(base: number): number {
116	  return Math.ceil((base * 11) / 10) + PROCESSING_FEE;
117	}
